create table customers
(
    user_id             uniqueidentifier                                not null
        constraint PK_customers
            primary key
        constraint FK_customers_users_user_id
            references users
            on delete cascade,
    phone_number        nvarchar(20),
    email               nvarchar(255),
    google_id           nvarchar(255),
    profile_picture_url nvarchar(255),
    created_at          datetime2 default '0001-01-01T00:00:00.0000000' not null,
    deleted_at          datetime2,
    modified_at         datetime2,
    point               int       default 0                             not null
)
go

create unique index IX_customers_email
    on customers (email)
    where [email] IS NOT NULL
go

create unique index IX_customers_google_id
    on customers (google_id)
    where [google_id] IS NOT NULL
go

create unique index IX_customers_phone_number
    on customers (phone_number)
    where [phone_number] IS NOT NULL
go

